const express = require('express');
const morgan = require('morgan');
const fs = require('fs');
const path = require('path');
const app = express();

const logDirectory = path.join(__dirname, 'logs');
fs.existsSync(logDirectory) || fs.mkdirSync(logDirectory);

const accessLogStream = fs.createWriteStream(path.join(logDirectory, 'access.log'), { flags: 'a' });

app.use(express.json());
app.use(morgan(':remote-addr - :remote-user ":method :url HTTP/:http-version" :status :res[content-length] - :response-time ms - :req[header] - :req[username]', {
  stream: accessLogStream,
  skip: (req, res) => res.statusCode < 400
}));

app.post('/log', (req, res) => {
  const { username, customHeader } = req.body;
  const ip = req.ip;
  const logMessage = `User: ${username}, IP: ${ip}, Custom Header: ${customHeader}`;
  
  fs.appendFile(path.join(logDirectory, 'audit.log'), logMessage + '\n', (err) => {
    if (err) {
      return res.status(500).send('Error logging data');
    }
    res.status(200).send('Data logged successfully');
  });
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});